#include <iostream>
#include <string>

template <typename T>
T findMin(T val1, T val2) {
    return (val1 < val2) ? val1 : val2;
}

int main() {
    std::cout << findMin(10, 5) << std::endl;
    std::cout << findMin(3.14, 2.71) << std::endl;
    std::cout << findMin(std::string("apple"), std::string("banana")) << std::endl;
    std::cout << findMin(std::string("zebra"), std::string("yak")) << std::endl;
    return 0;
}
